### 1. src/lib/organizations/org-context.tsx — Org context provider

Create a React context that provides org info to all org-scoped pages.

```typescript
"use client"

import React, { createContext, useContext, useState, useEffect, useCallback } from "react"

interface OrgContextValue {
  groupDid: string
  handle: string
  displayName: string
  role: "owner" | "admin" | "member"
  isLoading: boolean
  error: string | null
  refetch: () => void
}

const OrgContext = createContext<OrgContextValue | undefined>(undefined)

export function OrgProvider({ groupDid, children }: { groupDid: string; children: React.ReactNode }) {
  const [data, setData] = useState<{ handle: string; displayName: string; role: "owner" | "admin" | "member" } | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const fetchOrg = useCallback(async () => {
    try {
      setIsLoading(true)
      setError(null)
      const res = await fetch(\`/api/organizations/\${encodeURIComponent(groupDid)}\`)
      if (!res.ok) {
        const data = await res.json().catch(() => ({}))
        throw new Error(data.error ?? "Failed to load organization")
      }
      const org = await res.json()
      setData({ handle: org.handle, displayName: org.displayName, role: org.role })
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load organization")
    } finally {
      setIsLoading(false)
    }
  }, [groupDid])

  useEffect(() => { fetchOrg() }, [fetchOrg])

  const value: OrgContextValue = {
    groupDid,
    handle: data?.handle ?? "",
    displayName: data?.displayName ?? "",
    role: data?.role ?? "member",
    isLoading,
    error,
    refetch: fetchOrg,
  }

  return <OrgContext.Provider value={value}>{children}</OrgContext.Provider>
}

export function useOrg(): OrgContextValue {
  const ctx = useContext(OrgContext)
  if (!ctx) throw new Error("useOrg must be used within an OrgProvider")
  return ctx
}
```

